// Time:  O(nlog*n) ~= O(n), n is the length of S
// Space: O(n)

class Solution {
public:
    string smallestEquivalentString(string A, string B, string S) {
        UnionFind union_find(26);
        for (int i = 0; i < A.length(); ++i) {
            union_find.union_set(A[i] - 'a', B[i] - 'a');
        }
        string result;
        for (int i = 0; i < S.length(); ++i) {
            const auto& parent = union_find.find_set(S[i] - 'a');
            result.push_back(parent + 'a');
        }
        return result;
    }

private:
    class UnionFind {
    public:
        UnionFind(const int n) : set_(n) {
            iota(set_.begin(), set_.end(), 0);
        }

        int find_set(const int x) {
           if (set_[x] != x) {
               set_[x] = find_set(set_[x]);  // Path compression.
           }
           return set_[x];
        }

        void union_set(const int x, const int y) {
            int x_root = find_set(x), y_root = find_set(y);
            if (x_root != y_root) {
                set_[max(x_root, y_root)] = min(x_root, y_root);
            }
        }

    private:
        vector<int> set_;
    };
};

# Time:  O(nlog*n) ~= O(n), n is the length of S
# Space: O(n)

class UnionFind(object):
    def __init__(self, n):
        self.set = range(n)

    def find_set(self, x):
        if self.set[x] != x:
            self.set[x] = self.find_set(self.set[x])  # path compression.
        return self.set[x]

    def union_set(self, x, y):
        x_root, y_root = map(self.find_set, (x, y))
        if x_root == y_root:
            return False
        self.set[max(x_root, y_root)] = min(x_root, y_root)
        return True


class Solution(object):
    def smallestEquivalentString(self, A, B, S):
        """
        :type A: str
        :type B: str
        :type S: str
        :rtype: str
        """
        union_find = UnionFind(26)
        for i in xrange(len(A)):
            union_find.union_set(ord(A[i])-ord('a'), ord(B[i])-ord('a'))
        result = []
        for i in xrange(len(S)):
            parent = union_find.find_set(ord(S[i])-ord('a'))
            result.append(chr(parent+ord('a')))
        return "".join(result)
